library(haven); library(dplyr); library(purrr); library(labelled); library(readr); dir.create("data/output", showWarnings = FALSE, recursive = TRUE); harmonize_nssec <- function(x) { x[x == -999] <- -2; x[x == -94] <- -8; x[x %in% c(-99, -98)] <- -3; positive_vals <- x > 0 & !is.na(x); x[positive_vals] <- floor(x[positive_vals]); invalid_positive <- x > 17 & x < 100; x[invalid_positive] <- NA; x[is.na(x)] <- -3; return(x) }; create_labelled_factor <- function(x) { all_labels <- c("Employers in large organisations" = 1, "Higher managerial occupations" = 2, "Higher professional occupations" = 3, "Lower professional occupations" = 4, "Lower managerial occupations" = 5, "Higher supervisory occupations" = 6, "Intermediate occupations" = 7, "Employers in small organisations" = 8, "Own account workers" = 9, "Lower supervisory occupations" = 10, "Lower technical craft" = 11, "Semi routine occupations" = 12, "Routine occupations" = 13, "Never worked/Long-term unemployed" = 14, "Full-time students" = 15, "Not classified or inadequately stated" = 16, "Not classifiable for other reasons" = 17, "Not applicable" = -1, "Script error/information lost" = -2, "Not asked/not interviewed" = -3, "Prefer not to say" = -7, "Don't know/insufficient information" = -8, "Refusal" = -9); unique_vals <- sort(unique(x[!is.na(x)])); present_labels <- all_labels[all_labels %in% unique_vals]; x_labelled <- labelled(x, labels = present_labels); x_factor <- as_factor(x_labelled); return(x_factor) }; w1 <- read_delim("data/input/wave_one_lsype_family_background_2020.tab", delim = "\t", show_col_types = FALSE); w1_clean <- w1 %>% select(NSID, W1nsseccatmum, W1nsseccatdad) %>% mutate(nssecma14 = harmonize_nssec(W1nsseccatmum), nssecpa14 = harmonize_nssec(W1nsseccatdad)) %>% select(NSID, nssecma14, nssecpa14); w2 <- read_delim("data/input/wave_two_lsype_family_background_2020.tab", delim = "\t", show_col_types = FALSE); w2_clean <- w2 %>% select(NSID, W2nsseccatmum, W2nsseccatdad) %>% mutate(nssecma15 = harmonize_nssec(W2nsseccatmum), nssecpa15 = harmonize_nssec(W2nsseccatdad)) %>% select(NSID, nssecma15, nssecpa15); w3 <- read_delim("data/input/wave_three_lsype_family_background_2020.tab", delim = "\t", show_col_types = FALSE); w3_clean <- w3 %>% select(NSID, W3cnsseccatmum, W3cnsseccatdad) %>% mutate(nssecma16 = harmonize_nssec(W3cnsseccatmum), nssecpa16 = harmonize_nssec(W3cnsseccatdad)) %>% select(NSID, nssecma16, nssecpa16); w4 <- read_delim("data/input/wave_four_lsype_family_background_2020.tab", delim = "\t", show_col_types = FALSE); w4_clean <- w4 %>% select(NSID, w4cnsseccatmum, w4cnsseccatdad) %>% mutate(nssecma17 = harmonize_nssec(w4cnsseccatmum), nssecpa17 = harmonize_nssec(w4cnsseccatdad)) %>% select(NSID, nssecma17, nssecpa17); w5 <- read_delim("data/input/wave_five_lsype_family_background_2020.tab", delim = "\t", show_col_types = FALSE); w5_clean <- w5 %>% select(NSID, w5Cnsseccatmum, w5Cnsseccatdad) %>% mutate(nssecma18 = harmonize_nssec(w5Cnsseccatmum), nssecpa18 = harmonize_nssec(w5Cnsseccatdad)) %>% select(NSID, nssecma18, nssecpa18); cleaned_data <- w1_clean %>% full_join(w2_clean, by = "NSID") %>% full_join(w3_clean, by = "NSID") %>% full_join(w4_clean, by = "NSID") %>% full_join(w5_clean, by = "NSID"); nssec_vars <- c("nssecma14", "nssecpa14", "nssecma15", "nssecpa15", "nssecma16", "nssecpa16", "nssecma17", "nssecpa17", "nssecma18", "nssecpa18"); for (var in nssec_vars) { cleaned_data[[var]] <- create_labelled_factor(cleaned_data[[var]]) }; final_data <- cleaned_data %>% select(NSID, nssecma14, nssecpa14, nssecma15, nssecpa15, nssecma16, nssecpa16, nssecma17, nssecpa17, nssecma18, nssecpa18); write_csv(final_data, "data/output/cleaned_data.csv"); cat("Data cleaning complete.\n"); cat("Number of rows:", nrow(final_data), "\n"); cat("Number of columns:", ncol(final_data), "\n"); cat("Output written to: data/output/cleaned_data.csv\n")